const std = @import("std");
const writer = @import("writer.zig");

test "round trip preserves the header comment" {
    var buf: [256]u8 = undefined;
    const output = try writer.serialize(&buf, kv);
    try std.testing.expect(std.mem.indexOf(u8, output, "# header comment") != null);
}

const std = @import("std");
const writer = @import("writer.zig");

test "serialize emits the re-prefixed comment" {
    var buf: [256]u8 = undefined;
    const output = try writer.serialize(&buf, kv);
    try std.testing.expectEqualStrings("# inline comment", output);
}

const std = @import("std");
const math = @import("math.zig");

test "add sums two integers" {
    try std.testing.expectEqual(math.add(2, 3), 5);
}

const std = @import("std");

test "a plain literal comparison is not an output contract" {
    const greeting = "hello";
    try std.testing.expectEqualStrings("hello", greeting);
}
